import { type Timeframe, type TimeValue } from '../types/time.js';

type TimeBoundaryErrorKey = Extract<
  TimeErrorKey,
  'maxBoundary' | 'minBoundary' | 'minMaxBoundary'
>;

type TimeBoundaryMessageValues = {
  min: string;
  max: string;
};

type TimeBoundaryMessageData = {
  errorKey: TimeBoundaryErrorKey;
  values: TimeBoundaryMessageValues;
};

/** @internal */
export type ValidateOptions = {
  formMessageDispatch?: Dispatch<FormFieldMessagesReducerAction>;
  formerError?: TimeErrorKey;
  precision?: Precision;
  showError?: boolean;
  checkOrder?: boolean;
  ref?: RefObject<unknown>;
  expectedFormat?: string;
  valueMode?: 'single' | 'timeframeSelector' | 'dateTimePicker';
  required?: boolean;
  /** Optional per-key message overrides. Falls back to built-in defaults for any omitted keys. @internal */
  errorMessages?: Partial<Record<TimeErrorKey, MessageDescriptor>>;
};

/**
 * Checks if a date is outside the given min and/or max bounds.
 * @internal
 */
export function isOutOfBounds(
  date?: string | Date,
  min?: TimeValue | null,
  max?: TimeValue | null,
): TimeErrorKey | undefined {
  // All parse times here need to use the same _now_ date, to not be subject
  // to millisecond differences during parsing.
  const relativeNow = TZDateMini.tz(getTimezone()).getTime();

  const newDate =
    typeof date === 'string'
      ? parseTimeAsTimeValue(date, relativeNow)?.absoluteDate
      : date;

  if (!newDate) {
    return undefined;
  }

  // Re-evaluate relative expressions using the same "now" as the value so
  // that min/max stay temporally consistent with the date being checked.
  // Using a stale absoluteDate from a midnight refresh would cause spurious
  // out-of-bounds errors when the value is evaluated at the current time.
  const minDate =
    min?.type === 'expression'
      ? parseTimeAsTimeValue(min.value, relativeNow)?.absoluteDate
      : min?.absoluteDate;
  const maxDate =
    max?.type === 'expression'
      ? parseTimeAsTimeValue(max.value, relativeNow)?.absoluteDate
      : max?.absoluteDate;

  if (
    minDate &&
    maxDate &&
    (isBefore(newDate, minDate) || isAfter(newDate, maxDate))
  ) {
    return 'minMaxBoundary';
  }

  if (minDate && !maxDate && isBefore(newDate, minDate)) {
    return 'minBoundary';
  }

  if (!minDate && maxDate && isAfter(newDate, maxDate)) {
    return 'maxBoundary';
  }

  return undefined;
}
