/**
 * Checks whether any part of the given value falls outside the default Grail date range.
 */
function isValueOutsideGrailRange(
  value: { from: TimeValue | null; to: TimeValue | null } | TimeValue | null,
): boolean {
  if (!value) {
    return false;
  }

  const grailMinDate = new Date(GRAIL_MIN_DATE);
  const grailMaxDate = new Date(GRAIL_MAX_DATE);

  if (isTimeValue(value)) {
    if (!value.absoluteDate) {
      return false;
    }
    const date = new Date(value.absoluteDate);
    return isBefore(date, grailMinDate) || isAfter(date, grailMaxDate);
  }

  const fromDate = value.from?.absoluteDate
    ? new Date(value.from.absoluteDate)
    : null;
  const toDate = value.to?.absoluteDate
    ? new Date(value.to.absoluteDate)
    : null;

  return (
    (fromDate !== null &&
      (isBefore(fromDate, grailMinDate) || isAfter(fromDate, grailMaxDate))) ||
    (toDate !== null &&
      (isBefore(toDate, grailMinDate) || isAfter(toDate, grailMaxDate)))
  );
}

/**
 * Filters a GRAIL default min or max TimeValue.
 * Returns `undefined` when the limit is a default Grail boundary and the value
 * is within the Grail range (so the Grail limit should not appear in messages).
 * Custom (non-Grail) limits are always kept.
 */
function filterGrailTimeValue(
  value: { from: TimeValue | null; to: TimeValue | null } | TimeValue | null,
  limit?: TimeValue | null,
): TimeValue | null | undefined {
  if (!limit) {
    return limit;
  }

  const isGrailLimit =
    limit.value === GRAIL_MIN_DATE || limit.value === GRAIL_MAX_DATE;

  if (!isGrailLimit) {
    return limit;
  }

  return isValueOutsideGrailRange(value) ? limit : null;
}

function isTimeBoundaryErrorKey(
  errorKey?: TimeErrorKey,
): errorKey is TimeBoundaryErrorKey {
  return (
    errorKey === 'minBoundary' ||
    errorKey === 'maxBoundary' ||
    errorKey === 'minMaxBoundary'
  );
}

function parseLimit(
  limit?: TimeValue | string | null,
  relativeNow: number = TZDateMini.tz(getTimezone()).getTime(),
): TimeValue | null | undefined {
  if (typeof limit !== 'string') {
    return limit;
  }

  return parseTimeAsTimeValue(limit, relativeNow) ?? null;
}

function getBoundaryErrorKey(
  min?: TimeValue | null,
  max?: TimeValue | null,
): TimeBoundaryErrorKey | undefined {
  if (min && max) {
    return 'minMaxBoundary';
  }

  if (min) {
    return 'minBoundary';
  }

  if (max) {
    return 'maxBoundary';
  }

  return undefined;
}

/**
 * Gets the timeframe boundary message data while hiding default Grail limits
 * unless the current value actually exceeds the Grail range.
 * @internal
 */
export function getTimeBoundaryMessageData(
  value: { from: TimeValue | null; to: TimeValue | null } | TimeValue | null,
  min?: TimeValue | string | null,
  max?: TimeValue | string | null,
  precision: Precision = 'minutes',
  onlyWhenOutOfBounds: boolean = true,
): TimeBoundaryMessageData | undefined {
  const relativeNow = TZDateMini.tz(getTimezone()).getTime();
  const parsedMin = parseLimit(min, relativeNow);
  const parsedMax = parseLimit(max, relativeNow);
  const filteredMin = filterGrailTimeValue(value, parsedMin);
  const filteredMax = filterGrailTimeValue(value, parsedMax);

  const errorKey = onlyWhenOutOfBounds
    ? getOutOfBoundsErrorKey(value, filteredMin, filteredMax)
    : getBoundaryErrorKey(filteredMin, filteredMax);

  if (!isTimeBoundaryErrorKey(errorKey)) {
    return undefined;
  }

  const { min: formattedMin, max: formattedMax } = getFormattedMinMax(
    filteredMin?.value,
    filteredMax?.value,
    precision,
  );

  return {
    errorKey,
    values: {
      min: formattedMin,
      max: formattedMax,
    },
  };
}

/** validates a Timeframe or a TimeValue against their min and max borders */
function getOutOfBoundsErrorKey(
  updatedValue:
    | { from: TimeValue | null; to: TimeValue | null }
    | TimeValue
    | null,
  min?: TimeValue | null,
  max?: TimeValue | null,
): TimeErrorKey | undefined {
  // Range value
  if (
    updatedValue &&
    ('from' in updatedValue || 'to' in updatedValue) &&
    isTimeframe(updatedValue, 'range')
  ) {
    const fromErrorKey = isOutOfBounds(updatedValue?.from?.value, min, max);
    const toErrorKey = isOutOfBounds(updatedValue?.to?.value, min, max);
    return fromErrorKey || toErrorKey;
  }

  // Single value
  if (updatedValue && isTimeValue(updatedValue)) {
    return isOutOfBounds(updatedValue.value, min, max);
  }
}

function isInvalidOrder(value: Partial<Timeframe>): boolean {
  if (isFullTimeframe(value)) {
    const timezone = getTimezone();
    const fromTime = new TZDateMini(
      value.from?.absoluteDate,
      timezone,
    ).getTime();
    const toTime = new TZDateMini(value.to?.absoluteDate, timezone).getTime();
    if (value.from && value.to && fromTime >= toTime) {
      return true;
    }
  }
  return false;
}

function getInvalidErrorKey(
  value: { from: TimeValue | null; to: TimeValue | null } | TimeValue | null,
  valueMode?: 'single' | 'timeframeSelector' | 'dateTimePicker',
): TimeErrorKey | undefined {
  if (
    valueMode !== 'single' &&
    value &&
    !isTimeValue(value) &&
    (('from' in value && value.from !== undefined) ||
      ('to' in value && value.to !== undefined))
  ) {
    const isFromInvalid =
      value.from?.absoluteDate === '' && value.from?.value !== '';
    const isToInvalid = value.to?.absoluteDate === '' && value.to?.value !== '';

    if (isFromInvalid && isToInvalid) {
      return 'invalidFromTo';
    }
    if (isFromInvalid) {
      return 'invalidFrom';
    }
    if (isToInvalid) {
      return 'invalidTo';
    }
  }

  if (
    valueMode === 'single' &&
    value &&
    'absoluteDate' in value &&
    value.absoluteDate === '' &&
    value.value !== ''
  ) {
    return 'invalid';
  }

  return undefined;
}

/**
 * Determines the appropriate error key for a missing value.
 */
function getValueMissingErrorKey(
  value: { from: TimeValue | null; to: TimeValue | null } | TimeValue | null,
  valueMode?: 'single' | 'timeframeSelector' | 'dateTimePicker',
): TimeErrorKey | undefined {
  if (value === null) {
    if (valueMode === 'single') {
      return 'singleValueMissing';
    }

    if (valueMode === 'dateTimePicker') {
      return 'missingFromTo';
    }

    return 'valueMissing';
  }

  if (!isTimeValue(value) && value.from === null && value.to === null) {
    if (valueMode === 'dateTimePicker') {
      return 'missingFromTo';
    }

    return 'valueMissing';
  }

  if (valueMode !== 'single' && isPartialTimeframe(value)) {
    if (!value.from) {
      return 'missingFrom';
    }
    if (!value.to) {
      return 'missingTo';
    }
  }

  return undefined;
}

/**
 * Validates a Timeframe or a TimeValue against the provided constraints (min, max, required, order) and dispatches appropriate error messages.
 * @internal
 */
export function validate(
  value: { from: TimeValue | null; to: TimeValue | null } | TimeValue | null,
  min?: TimeValue | null,
  max?: TimeValue | null,
  options?: ValidateOptions,
): TimeErrorKey | undefined {
  const {
    formMessageDispatch,
    formerError: previousError,
    precision: validationPrecision = 'minutes',
    showError: showValidationError,
    checkOrder: shouldCheckOrder,
    ref: validationRef,
    expectedFormat: expectedValidationFormat = 'YYYY-MM-DD HH:mm:ss',
    valueMode: validationValueMode,
    required: isRequired,
    errorMessages,
  } = options ?? {};

  const timeBoundaryMessageData = getTimeBoundaryMessageData(
    value,
    min,
    max,
    validationPrecision,
  );

  const invalidOrderError =
    shouldCheckOrder && isInvalidOrder(value as Partial<Timeframe>)
      ? 'invalidOrder'
      : undefined;
  const invalidError = getInvalidErrorKey(value, validationValueMode);
  const valueMissingError = isRequired
    ? getValueMissingErrorKey(value, validationValueMode)
    : undefined;
  const outOfBoundsError = timeBoundaryMessageData?.errorKey;
  const errorKey =
    invalidOrderError ?? valueMissingError ?? outOfBoundsError ?? invalidError;

  if (errorKey) {
    const messageDef =
      errorMessages?.[errorKey] ?? DEFAULT_ERROR_MESSAGES[errorKey];
    // Only add the error message if the erroring input is already mounted
    validationRef?.current &&
      formMessageDispatch?.({
        type: FormFieldMessagesAction.ADDMESSAGE,
        payload: {
          id: errorKey,
          variant: 'error',
          messageType: 'formcontrol',
          message: (
            <FormattedMessage
              {...messageDef}
              values={{
                ...timeBoundaryMessageData?.values,
                expectedFormat: expectedValidationFormat,
              }}
            />
          ),
          validityStateKey: 'customError',
          showError: showValidationError,
        },
      });
  }

  // cleanup old error message
  if (previousError && previousError !== errorKey) {
    validationRef?.current &&
      formMessageDispatch?.({
        type: FormFieldMessagesAction.REMOVEMESSAGE,
        payload: {
          id: previousError,
          messageType: 'formcontrol',
        },
      });
  }

  return errorKey;
}
